// ===========================================
// W4 — Weekly Deferred Cleanup
// ===========================================
// Triggers Sunday 00:00 KST.
// Queries deferred quests with defer_count >= 7.
// Non-mandatory: auto-cancel.
// Mandatory: keep deferred with warning comment.
// If DeepSeek available, consult for cancel/keep decisions.
// Generates weekly deferred report and sends to LobeHub.
// References W5 as Error Workflow. Non-critical failure.

const config = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
  api_key: $env.PULSE_PLANE_API_KEY,
  daily_quest_project_id: $env.PULSE_DAILY_QUEST_PROJECT_ID,
  state_deferred: $env.PULSE_STATE_DEFERRED_ID,
  state_canceled: $env.PULSE_STATE_CANCELED_ID,
  deepseek_api_key: $env.PULSE_DEEPSEEK_API_KEY || '',
  deepseek_base_url: $env.PULSE_DEEPSEEK_BASE_URL || 'https://api.deepseek.com/v1',
  lobehub_webhook_url: $env.PULSE_LOBEHUB_WEBHOOK_URL || '',
};

const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';
const DRY_RUN = ($env.PULSE_DRY_RUN || 'false').toLowerCase() === 'true' || ($env.PULSE_DRY_RUN || 'false') === '1';

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const MAX_RETRIES = 3;
const RETRY_MS = 5000;
const withRetry = async (fn, ctx) => {
  for (let i = 1; i <= MAX_RETRIES; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] ${ctx} attempt ${i}/${MAX_RETRIES}: ${e.message}`);
      if (i === MAX_RETRIES) {
        const isTimeout = e.code === 'ETIMEDOUT' || e.code === 'ECONNABORTED' || e.message?.includes('timeout');
        const errorCode = isTimeout ? 'PLANE_API_TIMEOUT' : 'PLANE_API_ERROR';
        const err = new Error(`[${errorCode}] ${ctx}: ${e.message}`);
        err.errorCode = errorCode;
        throw err;
      }
      await sleep(RETRY_MS);
    }
  }
};

const apiGet = async (path) => {
  const res = await fetch(`${basePath}${path}`, { method: 'GET', headers });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const apiPatch = async (path, body) => {
  const res = await fetch(`${basePath}${path}`, { method: 'PATCH', headers, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const apiPost = async (path, body) => {
  const res = await fetch(`${basePath}${path}`, { method: 'POST', headers, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const decodeEntities = (s) => s.replace(/&quot;/g, '"').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&#39;/g, "'").replace(/&apos;/g, "'");
const extractMeta = (html) => {
  if (!html) return null;
  try {
    let m = html.match(/<pre><code\s+class="language-pulse-meta">([\s\S]*?)<\/code><\/pre>/);
    if (m) return JSON.parse(decodeEntities(m[1].trim()));
    m = html.match(/<pre><code>([\s\S]*?)<\/code><\/pre>/);
    if (m) { const c = decodeEntities(m[1].trim()); if (c.includes('"schema_version"')) return JSON.parse(c); }
    m = html.match(/```pulse-meta\s*\n([\s\S]*?)\n\s*```/);
    if (m) return JSON.parse(m[1].trim());
  } catch (e) { return null; }
  return null;
};

try {
  const projId = config.daily_quest_project_id;
  const nowStr = new Date().toLocaleTimeString('en-GB', { timeZone: tz, hour: '2-digit', minute: '2-digit' });
  const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });

  // Fetch all deferred quests
  const result = await withRetry(
    () => apiGet(`/projects/${projId}/issues/?per_page=100&expand=labels,state&state=${config.state_deferred}`),
    'Fetch deferred quests'
  );
  const allDeferred = result.results || result || [];

  // Filter for defer_count >= 7
  const chronic = allDeferred.filter(q => {
    const meta = extractMeta(q.description_html);
    return meta && (meta.defer_count || 0) >= 7;
  });

  if (chronic.length === 0) {
    console.log('[W4] No chronically deferred quests found (defer_count >= 7). Nothing to clean up.');
    // Still send a report
    const reportMessage = `\uD83D\uDDD1\uFE0F **Weekly Deferred Cleanup Report** (${todayStr})\n\nNo quests with 7+ deferrals found. All clear!\n\n_Total deferred quests remaining: ${allDeferred.length}_`;

    if (config.lobehub_webhook_url && !DRY_RUN) {
      try {
        await fetch(config.lobehub_webhook_url, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ message: reportMessage })
        });
      } catch (e) {
        console.log(`[W4] LobeHub notify failed (non-critical): ${e.message}`);
      }
    }

    return [{ json: { status: 'ok', chronic_count: 0, canceled: 0, kept: 0, total_deferred: allDeferred.length } }];
  }

  // Try DeepSeek for intelligent decisions
  let aiDecisions = null;
  if (config.deepseek_api_key) {
    try {
      const questSummary = chronic.map(q => {
        const meta = extractMeta(q.description_html);
        return {
          issue_id: q.id,
          name: q.name,
          defer_count: meta?.defer_count || 0,
          routine_mandatory: meta?.routine_mandatory || false,
          routine_priority: meta?.routine_priority || 'medium',
        };
      });

      const systemPrompt = '# W4: AI Deferred Quest Cleanup Decision\n\n## Role\n\nYou are a task hygiene assistant that evaluates chronically deferred quests and recommends whether each should be automatically canceled or kept.\n\n## Task\n\nGiven a list of deferred quests with `defer_count >= 7`, evaluate each quest and decide:\n1. **Cancel**: The quest has been deferred so many times it is unlikely to be completed. Remove it to reduce clutter.\n2. **Keep**: The quest is mandatory or has strategic importance and should remain deferred despite chronic deferral.\n\n## Decision Criteria\n\n- **Mandatory flag**: If `routine_mandatory` is `true`, strongly prefer keeping the quest. Only recommend canceling mandatory quests in exceptional circumstances.\n- **Defer count**: Higher defer counts suggest lower relevance. Quests deferred 10+ times with no mandatory flag are strong cancel candidates.\n- **Priority**: Higher priority quests (urgent, high) deserve more consideration before canceling.\n- **Quest name/context**: Use the quest name to infer importance. Vague or low-value names lean toward cancel.\n\n## Constraints\n\n- Each decision must include: `issue_id`, `name`, `action` ("cancel" or "keep"), and `rationale` (1-2 sentences).\n- Be conservative with mandatory quests — default to "keep" unless there is a compelling reason to cancel.\n- All output must be in English.\n\n## Output Format\n\nYou MUST respond with valid JSON in the following format:\n\n```json\n{\n  "decisions": [\n    {\n      "issue_id": "uuid",\n      "name": "Quest name",\n      "action": "cancel",\n      "rationale": "Brief reason for the decision."\n    }\n  ]\n}\n```\n';

      const aiRes = await fetch(`${config.deepseek_base_url}/chat/completions`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${config.deepseek_api_key}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          model: 'deepseek-chat',
          messages: [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: JSON.stringify({ quests: questSummary }) }
          ],
          response_format: { type: 'json_object' },
          temperature: 0.3,
          max_tokens: 2000
        })
      });

      if (aiRes.ok) {
        const aiData = await aiRes.json();
        const content = aiData.choices?.[0]?.message?.content;
        if (content) {
          aiDecisions = JSON.parse(content);
          console.log(`[W4] DeepSeek provided ${aiDecisions.decisions?.length || 0} cleanup decisions.`);
        }
      }
    } catch (e) {
      console.log(`[W4] DeepSeek consultation failed (non-critical): ${e.message}. Falling back to rule-based logic.`);
    }
  }

  // Process each chronic quest
  const canceledQuests = [];
  const keptQuests = [];

  for (const quest of chronic) {
    const meta = extractMeta(quest.description_html);
    const deferCount = meta?.defer_count || 0;
    const isMandatory = meta?.routine_mandatory || false;

    // Determine action: AI decision or rule-based fallback
    let action = 'cancel'; // default for non-mandatory
    if (isMandatory) action = 'keep'; // default for mandatory

    if (aiDecisions?.decisions) {
      const aiDecision = aiDecisions.decisions.find(d => d.issue_id === quest.id);
      if (aiDecision) {
        action = aiDecision.action === 'keep' ? 'keep' : 'cancel';
      }
    }

    if (action === 'cancel') {
      if (DRY_RUN) {
        console.log(`[DRY_RUN] Would cancel chronic deferred quest: ${quest.name} (defer_count: ${deferCount})`);
      } else {
        await withRetry(
          () => apiPatch(`/projects/${projId}/issues/${quest.id}/`, { state: config.state_canceled }),
          `Cancel chronic quest ${quest.id}`
        );
        await withRetry(
          () => apiPost(`/projects/${projId}/issues/${quest.id}/comments/`, {
            comment_html: `<p>\uD83D\uDDD1\uFE0F [${nowStr}] Auto-canceled: deferred ${deferCount}+ times</p>`
          }),
          `Comment on ${quest.id}`
        );
      }
      canceledQuests.push({ name: quest.name, defer_count: deferCount });
    } else {
      // Keep but add warning comment
      if (!DRY_RUN) {
        await withRetry(
          () => apiPost(`/projects/${projId}/issues/${quest.id}/comments/`, {
            comment_html: `<p>\u26A0\uFE0F [${nowStr}] Chronic deferral (count: ${deferCount}) \u2014 mandatory routine, kept deferred</p>`
          }),
          `Comment on ${quest.id}`
        );
      }
      keptQuests.push({ name: quest.name, defer_count: deferCount });
    }
  }

  // Generate weekly deferred report
  const dryTag = DRY_RUN ? ' [DRY_RUN]' : '';
  let report = `\uD83D\uDDD1\uFE0F **Weekly Deferred Cleanup Report**${dryTag} (${todayStr})\n\n`;

  if (canceledQuests.length > 0) {
    report += `**\uD83D\uDEAB Canceled** (${canceledQuests.length}):\n`;
    for (const q of canceledQuests) {
      report += `  \u2022 ${q.name} (deferred x${q.defer_count})\n`;
    }
    report += '\n';
  }

  if (keptQuests.length > 0) {
    report += `**\u26A0\uFE0F Kept (mandatory)** (${keptQuests.length}):\n`;
    for (const q of keptQuests) {
      report += `  \u2022 ${q.name} (deferred x${q.defer_count})\n`;
    }
    report += '\n';
  }

  const remainingDeferred = allDeferred.length - canceledQuests.length;
  report += `_Total deferred remaining: ${remainingDeferred}_`;

  // Send report to LobeHub
  if (config.lobehub_webhook_url && !DRY_RUN) {
    try {
      await fetch(config.lobehub_webhook_url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: report })
      });
      console.log('[W4] Weekly report sent to LobeHub.');
    } catch (e) {
      console.log(`[W4] LobeHub notify failed (non-critical): ${e.message}`);
    }
  } else if (DRY_RUN) {
    console.log(`[DRY_RUN] Would send weekly report to LobeHub:\n${report}`);
  }

  return [{ json: {
    status: 'ok',
    chronic_count: chronic.length,
    canceled: canceledQuests.length,
    kept: keptQuests.length,
    total_deferred: remainingDeferred,
    report,
    dry_run: DRY_RUN
  }}];
} catch (e) {
  const code = e.errorCode || 'SYSTEM_ERROR';
  console.log(`[W4] ERROR: [${code}] ${e.message}`);
  return [{ json: {
    status: 'error',
    error_code: code,
    message: e.message
  }}];
}
